Python — top-down Fibonacci with memoPython — bottom-up coin change (min coins) <pre><code>from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n: int) -&gt; int:
    if n &lt;= 1:
        return n
    return fib(n - 1) + fib(n - 2)
</code></pre> <pre><code>def coin_change(coins: list[int], amount: int) -&gt; int:
    inf = amount + 1
    dp = [0] + [inf] * amount
    for x in range(1, amount + 1):
        for c in coins:
            if c &lt;= x:
                dp[x] = min(dp[x], dp[x - c] + 1)
    return dp[amount] if dp[amount] != inf else -1
</code></pre>

Python — adjacency list DFSPython — BFS shortest path (unweighted) <pre><code>def dfs(graph: dict[int, list[int]], start: int) -&gt; set[int]:
    seen = set()

    def visit(u: int) -&gt; None:
        seen.add(u)
        for v in graph.get(u, []):
            if v not in seen:
                visit(v)

    visit(start)
    return seen
</code></pre> <pre><code>from collections import deque

def bfs_shortest(graph, src, dst):
    q = deque([(src, 0)])
    seen = {src}
    while q:
        u, d = q.popleft()
        if u == dst:
            return d
        for v in graph.get(u, []):
            if v not in seen:
                seen.add(v)
                q.append((v, d + 1))
    return -1
</code></pre>

Python — valid parenthesesPython — BFS tree level order <pre><code>def is_valid(s: str) -&gt; bool:
    stack: list[str] = []
    pairs = {")": "(", "}": "{", "]": "["}
    for ch in s:
        if ch in pairs:
            if not stack or stack.pop() != pairs[ch]:
                return False
        else:
            stack.append(ch)
    return not stack
</code></pre> <pre><code>from collections import deque

def level_order(root):
    if not root:
        return []
    out, q = [], deque([root])
    while q:
        node = q.popleft()
        out.append(node.val)
        if node.left:
            q.append(node.left)
        if node.right:
            q.append(node.right)
    return out
</code></pre>

Python — anagram check with countsPython — reverse words in-place list <pre><code>from collections import Counter

def is_anagram(a: str, b: str) -&gt; bool:
    return Counter(a) == Counter(b)
</code></pre> <pre><code>def reverse_words(chars: list[str]) -&gt; None:
    def rev(i: int, j: int) -&gt; None:
        while i &lt; j:
            chars[i], chars[j] = chars[j], chars[i]
            i += 1
            j -= 1

    rev(0, len(chars) - 1)
    start = 0
    for i in range(len(chars) + 1):
        if i == len(chars) or chars[i] == " ":
            rev(start, i - 1)
            start = i + 1
</code></pre>

